const FIELDS = ["tipo","municipio","uf","frequencia","classe","categoria","erp","entidade","carater","finalidade","lat","lng"] as const;

function buildStations(): RadioStation[] {
  const fnKeys = Object.keys(FANTASY_NAMES);
  return _D.map((r, i) => {
    const s: Record<string, unknown> = {};
    FIELDS.forEach((f, fi) => {
      const lookupKey = ["T","M","U","Q","C","F",null,"E","K","R",null,null][fi];
      s[f] = lookupKey ? (_L as Record<string, string[]>)[lookupKey][r[fi]] : r[fi];
    });
    const station = s as unknown as RadioStation;
    station._sid = i;
    station._mun = station.municipio.toLowerCase().normalize("NFD").replace(/[̀-ͯ]/g, "");
    station._ent = station.entidade ? station.entidade.toLowerCase() : "";
    station._nome = station._ent + " " + (station.frequencia || "");
    station._fantasy = "";
    // Build fantasy name index
    const ent = station._ent;
    if (ent) {
      const aliases: string[] = [];
      for (const fk of fnKeys) {
        for (const kw of FANTASY_NAMES[fk]) {
          if (ent.includes(kw)) { aliases.push(fk); break; }
        }
      }
      if (aliases.length) {
        station._nome += " " + aliases.join(" ");
        station._fantasy = aliases.map(a => a.replace(/w/g, c => c.toUpperCase())).join(" / ");
      }
    }
    return station;
  });
}

export const stations: RadioStation[] = buildStations();

// Pre-computed filter options
export const ALL_UFS = [...new Set(stations.map(s => s.uf))].sort();
export const ALL_CLASSES = [...new Set(stations.map(s => s.classe).filter(Boolean))].sort();
export const ALL_FINALIDADES = [...new Set(stations.map(s => s.finalidade).filter(Boolean))].sort();
